public void generateEDC() {
        // create a couple of strings to store the buffer for the XML
        StringBuilder fieldsBuilder = new StringBuilder();
        StringBuilder optionListsBuilder = new StringBuilder();

        // get the runsettings and codebookmanager
        RunSettings runSettings = RunSettings.getInstance();
        CodebookManager codebookManager = CodebookManager.getInstance();

        // retrieve the key and loop over the items
        String key = runSettings.getSelectedCodebookIdentifier();
        for (String itemId : runSettings.getSelectedItemIdentifiers(key)) {
            // retrieve the selected items for the item and add each item to the template
            List<String> selectedItemIdentifiers = runSettings.getSelectedItemSelectedIdentifiers(key, itemId);
            for (String selectedItemId : selectedItemIdentifiers) {
                if (codebookManager.codebookItemHasTerminology(key, selectedItemId)) {
                    createTerminologyItem(fieldsBuilder, optionListsBuilder, key, selectedItemId, selectedItemIdentifiers);
                } else {
                    createNonTerminologyItem(fieldsBuilder, key, selectedItemId, selectedItemIdentifiers);
                }
            }
        }

        // create the full XML for Castor
        StringBuilder fullXML = new StringBuilder();
        String stepId = generateUUID();
        String phaseId = generateUUID();
        buildXMLForFormPart1(fullXML, stepId, phaseId);
        fullXML.append("<fields>");
        fullXML.append(fieldsBuilder.toString());
        fullXML.append("</fields>");
        buildXMLForFormPart2(fullXML, stepId, phaseId);
        buildXMLForFormPart3(fullXML, "Castor");
        fullXML.append("<lookupTable/>");
        buildXMLForFormPart4(fullXML, stepId, phaseId);
        fullXML.append("</xml>");

        // write the file to disk
        writeFile(fullXML);
    }

