public static void setColumnIndexes(PlannerContext context, AbstractExpression input, PlanColumn column) {
        if (input == null) {
            return;
        }

        // recursive call
        setColumnIndexes(context, input.m_left, column);
        setColumnIndexes(context, input.m_right, column);

        // actual work
        if (input instanceof TupleValueExpression) {
            final TupleValueExpression expr = (TupleValueExpression) input;
            final String tableName = expr.getTableName();
            final String columnName = expr.getColumnName();
            if (column.originTableName().equals(tableName)) {
                if (column.getDisplayName().equals(columnName)) {
                    expr.setColumnIndex(column.getIndex());
                    return;
                }
            }
        }

    }

