        for (long trans : savingsInstantTransitions) {
            out.writeLong(trans);
        }
        for (ZoneOffset offset : wallOffsets) {
            out.writeObject(offset);
        }
        out.writeByte(lastRules.length);
        for (ZoneOffsetTransitionRule rule : lastRules) {
            rule.writeExternal(out);
        }
    }

